// Input: msg.payload from PostgreSQL node (array of rows from the query)
let rows = msg.payload;

// Initialize the result object for devices
let devices = {};

// Initialize a temporary object for commands to deduplicate by id
let commandMap = {};

// Initialize an object to track infrared slaves and their device numbers
let infraredSlaves = {};

// First pass: Build devices, collect unique commands, and track infrared slaves
rows.forEach(row => {
    let deviceNumber = row.device_number;

    // Handle device mapping
    if (deviceNumber) {
        // Initialize device entry if it doesn't exist
        if (!devices[deviceNumber]) {
            devices[deviceNumber] = {
                deviceId: row.device_id,
                infraredId: row.infrared_id,
                energyId: row.energy_id,
                type: "remote_device",
                commands: []
            };
        }

        // Update attributes if present (in case of multiple rows for the same device_number)
        if (row.device_id) {
            devices[deviceNumber].deviceId = row.device_id;
        }
        if (row.infrared_id) {
            devices[deviceNumber].infraredId = row.infrared_id;
        }
        if (row.energy_id) {
            devices[deviceNumber].energyId = row.energy_id;
        }
    }

    // Collect infrared slave data (id and device numbers)
    if (row.infrared_id && row.infrared_name) {
        if (!infraredSlaves[row.infrared_id]) {
            // Extract device numbers from the infrared slave name (e.g., "RM 32" -> ["32"])
            let deviceNumbers = row.infrared_name.match(/\d+/g) || [];
            infraredSlaves[row.infrared_id] = {
                name: row.infrared_name,
                deviceNumbers: deviceNumbers
            };
        }
    }

    // Collect button/command data, deduplicate by button_id
    if (row.button_id) {
        let command = {
            id: row.button_id,
            name: row.button_name,
            slaveId: row.rfir_slave_id,
            commandId: row.command_id,
            remoteId: row.remote_id
        };
        if (!commandMap[row.button_id]) {
            commandMap[row.button_id] = command;
        }
    }
});

// Convert commandMap to an array
