// Input: msg.payload from PostgreSQL node (array of rows from the query)
let rows = msg.payload;

// Initialize the result object for devices
let devices = {};

// Initialize a temporary object for commands to deduplicate by id
let commandMap = {};

// First pass: Build devices and collect unique commands
rows.forEach(row => {
    let deviceNumber = row.device_number;

    // Handle device mapping
    if (deviceNumber) {
        // Initialize device entry if it doesn't exist
        if (!devices[deviceNumber]) {
            devices[deviceNumber] = {
                deviceId: row.device_id,
                infraredId: row.infrared_id,
                energyId: row.energy_id,
                commands: [] // Initialize an empty commands array
            };
        }

        // Update attributes if present (in case of multiple rows for the same device_number)
        if (row.device_id) {
            devices[deviceNumber].deviceId = row.device_id;
        }
        if (row.infrared_id) {
            devices[deviceNumber].infraredId = row.infrared_id;
        }
        if (row.energy_id) {
            devices[deviceNumber].energyId = row.energy_id;
        }
    }

    // Collect button/command data, deduplicate by button_id
    if (row.button_id) {
        let command = {
            id: row.button_id,
            name: row.button_name,
            slaveId: row.rfir_slave_id, // From rfir_devices, links to infrared slave
            commandId: row.command_id,
            remoteId: row.remote_id
        };
        // Only add the command if we haven't seen this button_id before
        if (!commandMap[row.button_id]) {
            commandMap[row.button_id] = command;
        }
    }
});

// Convert commandMap to an array
let allCommands = Object.values(commandMap);

// Second pass: Assign commands to devices based on infraredId
Object.keys(devices).forEach(deviceNumber => {
    let device = devices[deviceNumber];
    if (device.infraredId) {
        // Find all commands where slaveId matches the device's infraredId
        device.commands = allCommands.filter(command => command.slaveId === device.infraredId);
    }
});

// Set the output (only the devices hash map, now with deduplicated commands embedded)
msg.payload = devices;
return msg;

// Input: msg.payload contains the telemetry data
// Devices and infrared mapping are stored in flow context
const devices = flow.get('devices') || {};
const infraredMapping = flow.get('infraredMapping') || {};

// Extract telemetry data
let telemetryPayload = msg.payload;
let messageType = telemetryPayload.message_type;
let slaveId = parseInt(telemetryPayload.id); // Ensure slaveId is a number
let telemetryOutput = {};

// Handle different message types
if (messageType === "channel_update") {
    // Handle presence sensor telemetry (for devices like "32 - Presença")
    let presenceValue = 0; // Default value

    // Find the presence channel (id: 0)
    let presenceChannel = telemetryPayload.channels.find(channel => channel.id === 0);
    if (presenceChannel) {
        presenceValue = presenceChannel.input;
    }

    // Determine status: true if value is 0, false if value > 0
    let status = presenceValue === 0;

    // Get the device numbers associated with this infrared slave
    let targetDeviceNumbers = infraredMapping[slaveId] || [];

    // If targetDeviceNumbers is empty, fall back to scanning all presence devices
    if (targetDeviceNumbers.length === 0) {
        Object.keys(devices).forEach(deviceName => {
            let device = devices[deviceName];
            if (device.type === "presence_sensor" && device.infraredId === slaveId) {
                telemetryOutput[deviceName] = [
                    {
                        ts: new Date().getTime(),
                        values: {
                            status: status
                        }
                    }
                ];
            }
        });
    } else {
        // Find presence devices with matching infraredId and name derived from targetDeviceNumbers
        targetDeviceNumbers.forEach(deviceNumber => {
            let presenceDeviceName = `${deviceNumber} - Presença`;
            let device = devices[presenceDeviceName];
            if (device) {
                if (device.type === "presence_sensor" && device.infraredId === slaveId) {
                    telemetryOutput[presenceDeviceName] = [
                        {
                            ts: new Date().getTime(),
                            values: {
                                status: status
                            }
                        }
                    ];
                }
            }
        });
    }
} else if (messageType === "infrared_update") {
    // Handle infrared device telemetry (for the specific device matching the slave's name)
    let temperature = telemetryPayload.temperature !== undefined ? telemetryPayload.temperature : telemetryPayload.value;

    if (temperature !== undefined) {
        let targetDeviceNumbers = infraredMapping[slaveId] || [];

        Object.keys(devices).forEach(deviceName => {
            let device = devices[deviceName];
            if (
                device.type === "remote_device" &&
                device.infraredId === slaveId &&
                targetDeviceNumbers.includes(deviceName)
            ) {
                telemetryOutput[deviceName] = [
                    {
                        ts: new Date().getTime(),
                        values: {
                            temperature: temperature
                        }
                    }
                ];
            }
        });
    }
}

// Set the output
msg.payload = telemetryOutput;
return msg;

const bufferKey = 'latestMessages';
const lastSentKey = 'lastSentTimes';

const latestMessages = context.get(bufferKey) || {};
const lastSentTimes = context.get(lastSentKey) || {};

// Get the TTL from flow context or default to 5000ms
const deviceTTL = flow.get('deviceTTL') || 5000;
const now = Date.now();

// Handle "FLUSH" payload
if (typeof msg.payload === 'string' && msg.payload === 'FLUSH') {
    const newPayload = {};

    // Flush messages for devices whose TTL has expired
    for (const [deviceName, telemetry] of Object.entries(latestMessages)) {
        const lastSentTime = lastSentTimes[deviceName] || 0;
        if (now - lastSentTime >= deviceTTL) {
            newPayload[deviceName] = [telemetry];
            lastSentTimes[deviceName] = now;
            // Clear the flushed message
            delete latestMessages[deviceName];
        }
    }

    // Save the cleaned states to context
    context.set(bufferKey, latestMessages);
    context.set(lastSentKey, lastSentTimes);

    return Object.keys(newPayload).length > 0 ? { payload: newPayload } : null;
}

// Process normal payloads
if (typeof msg.payload === 'object') {
    // Update the latest message for each device
    for (const [deviceName, telemetryArray] of Object.entries(msg.payload)) {
        if (telemetryArray.length > 0) {
            latestMessages[deviceName] = {
                ...latestMessages[deviceName],
                ...telemetryArray[telemetryArray.length - 1],
            }
        }
    }

    context.set(bufferKey, latestMessages);
}

return null;

const keys = Object.keys(msg.payload);

const newPayload = keys.reduce((acc, key) => {
    acc[`${key} (Raiz Educação)`] = msg.payload[key];
    return acc;
}, {});

msg.payload = newPayload;
return msg;

// Input: msg.payload contains the telemetry data
// Devices, infrared mapping, and three-phase mapping are stored in flow context
const devices = flow.get('devices') || {};
const infraredMapping = flow.get('infraredMapping') || {};
const threePhaseMapping = flow.get('threePhaseMapping') || {};
const presenceOverrides = flow.get('presenceOverrides') || {};

// Extract telemetry data
let telemetryPayload = msg.payload;
let messageType = telemetryPayload.message_type;
let slaveId = parseInt(telemetryPayload.id); // Ensure slaveId is a number
let telemetryOutput = {};

// Handle different message types
if (messageType === "channel_update") {
    // Handle presence sensor telemetry
    telemetryPayload.channels.forEach(channel => {
        let channelId = channel.id;
        let presenceValue = channel.value;
        let deviceNamesToProcess = [];
        let isOverrideChannel = false;

        // First, check for override mappings for this specific slave_id + channel combination
        Object.keys(presenceOverrides).forEach(deviceNumber => {
            let override = presenceOverrides[deviceNumber];
            if (override.slave_id === slaveId && override.channel === channelId) {
                let presenceDeviceName = `${deviceNumber} - Presença`;
                if (devices[presenceDeviceName]) {
                    deviceNamesToProcess.push(presenceDeviceName);
                    isOverrideChannel = true;
                    node.warn("TELEMETRY OVERRIDE: Found override for device " + deviceNumber + " on slave " + slaveId + ", channel " + channelId + ", value=" + presenceValue);
                }
            }
        });

        // If no overrides found and this is channel 0, use normal mapping
        if (deviceNamesToProcess.length === 0 && channelId === 0) {
            // Get the device numbers associated with this infrared slave
            let targetDeviceNumbers = infraredMapping[slaveId] || [];

            // If targetDeviceNumbers is empty, fall back to scanning all presence devices
            if (targetDeviceNumbers.length === 0) {
                Object.keys(devices).forEach(deviceName => {
                    let device = devices[deviceName];
                    let deviceNumber = deviceName.replace(" - Presença", "");
                    let isOverridden = presenceOverrides[deviceNumber] && presenceOverrides[deviceNumber].slave_id !== slaveId;

                    if (device.type === "presence_sensor" && device.infraredId === slaveId && !isOverridden) {
                        deviceNamesToProcess.push(deviceName);
                    }
                });
            } else {
                // Find presence devices with matching infraredId and name derived from targetDeviceNumbers
                targetDeviceNumbers.forEach(deviceNumber => {
                    let presenceDeviceName = `${deviceNumber} - Presença`;
                    let device = devices[presenceDeviceName];
                    let isOverridden = presenceOverrides[deviceNumber] && presenceOverrides[deviceNumber].slave_id !== slaveId;

                    if (device && device.type === "presence_sensor" && device.infraredId === slaveId && !isOverridden) {
                        deviceNamesToProcess.push(presenceDeviceName);
                    }
                });
            }
        }

        // Determine status based on whether this is an override or normal device
        let status;
        if (isOverrideChannel) {
            // Override logic: 100 = presence detected, 0 = no presence
            status = presenceValue === 100;
            node.warn("TELEMETRY OVERRIDE: Using override logic - value=" + presenceValue + ", status=" + status);
        } else {
            // Normal logic: 0 = presence detected, non-0 = no presence
            status = presenceValue === 0;
        }

        // Add telemetry for all devices to process
        deviceNamesToProcess.forEach(deviceName => {
            telemetryOutput[deviceName] = [
                {
                    ts: new Date().getTime(),
                    values: {
                        status: status
                    }
                }
            ];
            if (isOverrideChannel) {
                node.warn("TELEMETRY OVERRIDE OUTPUT: " + deviceName + " -> status=" + status);
            }
        });
    });
} else if (messageType === "infrared_update") {
    // Handle infrared device telemetry (for the specific device matching the slave's name)
    let temperature = telemetryPayload.temperature !== undefined ? telemetryPayload.temperature : telemetryPayload.value;

    if (temperature !== undefined) {
        let targetDeviceNumbers = infraredMapping[slaveId] || [];

        Object.keys(devices).forEach(deviceName => {
            let device = devices[deviceName];
            if (
                device.type === "remote_device" &&
                device.infraredId === slaveId &&
                targetDeviceNumbers.includes(deviceName)
            ) {
                telemetryOutput[deviceName] = [
                    {
                        ts: new Date().getTime(),
                        values: {
                            temperature: temperature
                        }
                    }
                ];
            }
        });
    }
} else if (messageType === "consumption") {
    // Handle energy consumption telemetry (for devices associated with the three-phase sensor)
    let phases = telemetryPayload.phases || {};

    // Get the device numbers associated with this three-phase sensor
    let targetDeviceNumbers = threePhaseMapping[slaveId] || [];

    if (targetDeviceNumbers.length >= 3) {
        // Map phases to devices: a -> first device, b -> second device, c -> third device

        let phaseMapping = {
            a: targetDeviceNumbers[0], // e.g., "3"
            b: targetDeviceNumbers[1], // e.g., "1"
            c: targetDeviceNumbers[2] // e.g., "11"
        };

        // Process each phase
        ['a', 'b', 'c'].forEach(phase => {
            let deviceNumber = phaseMapping[phase];
            let device = devices[deviceNumber];
            let consumptionValue = phases[phase] !== undefined ? phases[phase] : 0;

            if (device && device.type === "remote_device" && device.energyId === slaveId) {
                telemetryOutput[deviceNumber] = [
                    {
                        ts: new Date().getTime(),
                        values: {
                            consumption: consumptionValue
                        }
                    }
                ];
            }
        });
    }
}

// Set the output
msg.payload = telemetryOutput;
return msg;

