}

const currentTimeSP = convertToSaoPaulo(new Date());
const currDate = getDateFromTime(currentTimeSP, '00:00');

let shouldActivate = false;
let command_id = null;
let slave_id = null;

for (let i = 0; i < schedules.length; i++) {
  const schedule = schedules[i];
  const scheduleTime = getDateFromTime(currentTimeSP, schedule.time);
  const days = schedule.daysWeek;
  const holidayBool = schedule.holiday;

  const currWeekDay = currentTimeSP.toLocaleString('en-US', {
    weekday: 'short',
    timeZone: 'America/Sao_Paulo'
  }).toLowerCase();
  const currentTimeStr = convertHoursMinutes(currentTimeSP.getTime());
  const scheduleTimeStr = convertHoursMinutes(scheduleTime.getTime());

  // Unique key for this schedule
  const scheduleKey = `${currentKey}:${i}`;

  // Check if command was already sent in this minute
  const lastSent = lastSentCommands[scheduleKey];
  const alreadySentThisMinute = lastSent && lastSent.time === currentTimeStr;

  if (!alreadySentThisMinute) {
    if (holidayBool) {
      if (storedHolidaysDays.length > 0) {
        for (const holidayDay of storedHolidaysDays) {
          const holidayDate = new Date(transformDate(holidayDay));
          if (currDate.getTime() === holidayDate.getTime()) {
            if (currentTimeStr === scheduleTimeStr) {
              shouldActivate = true;
              command_id = schedule.command_id;
              slave_id = schedule.slave_id;
              lastSentCommands[scheduleKey] = { time: currentTimeStr };
            }
          }
        }
      }
    }

    if (days[currWeekDay]) {
      if (currentTimeStr === scheduleTimeStr) {
        shouldActivate = true;
        command_id = schedule.command_id;
        slave_id = schedule.slave_id;
        lastSentCommands[scheduleKey] = { time: currentTimeStr };
      }
    }

    if (excludedDays.length > 0) {
      for (const excludedDay of excludedDays) {
        const excludedDate = new Date(transformDate(excludedDay));
        if (currDate.getTime() === excludedDate.getTime()) {
          shouldActivate = false;
          command_id = null;
          slave_id = null;
          delete lastSentCommands[scheduleKey];
        }
      }
    }
  }
}

if (currIndex >= (keys.length - 1)) {
