let currIndex = this.currIndex || 0;



const storedSchedules = flow.get('stored_ir_schedules') || {};
const storedExcludedDays = flow.get('stored_excludedDays') || {};
const storedHolidaysDays = flow.get('stored_holidays') || [];
let lastSentCommands = flow.get('lastSentCommands') || {};

const keys = Object.keys(storedSchedules);

if (keys.length === 0) {
    node.warn('No IR schedules found in stored_ir_schedules');
    return null;
}

const currentKey = keys[currIndex];
const schedules = Array.isArray(storedSchedules[currentKey]) ? storedSchedules[currentKey] : [];

if (schedules.length === 0) {
    node.warn(`No schedules for device ${currentKey}`);
}

// Sort schedules by time to process earlier times first
const sortedSchedules = schedules
  .map((s, i) => ({ ...s, originalIndex: i }))
  .sort((a, b) => {
    const timeA = a.time.split(':').map(Number);
    const timeB = b.time.split(':').map(Number);
    return timeA[0] * 60 + timeA[1] - (timeB[0] * 60 + timeB[1]);
  });

let excludedDays = [];
if (currentKey in storedExcludedDays) {
  excludedDays = storedExcludedDays[currentKey].map((item) => item.excludedDays);
}

const currentTimeSP = convertToSaoPaulo(new Date());
const currDate = getDateFromTime(currentTimeSP, '00:00');

let shouldActivate = false;
let command_id = null;
let slave_id = null;

// node.warn(`Processing device ${currentKey} at ${currentTimeSP.toISOString()} (SP time)`);
// node.warn(`lastSentCommands for ${currentKey}: ${JSON.stringify(lastSentCommands)}`);

for (let { time: scheduleTimeStr, daysWeek, holiday, command_id: cmdId, slave_id: slvId, originalIndex } of sortedSchedules) {
  const scheduleTime = getDateFromTime(currentTimeSP, scheduleTimeStr);
  if (isNaN(scheduleTime.getTime())) {
    node.warn(`Invalid schedule time ${scheduleTimeStr} for ${currentKey}`);
    continue;
  }

  const currWeekDay = currentTimeSP.toLocaleString('en-US', {
    weekday: 'short',
    timeZone: 'America/Sao_Paulo'
  }).toLowerCase();
  const currentTimeStr = convertHoursMinutes(currentTimeSP.getTime());

  // Use time-based scheduleKey to distinguish schedules
  const scheduleKey = `${currentKey}:${scheduleTimeStr}`;

  let lastSent = lastSentCommands[scheduleKey] || { sendCount: 0, lastSentTime: null, scheduledTime: scheduleTimeStr, date: null };

  // Handle legacy lastSentCommands format (e.g., { time: "19:01" })
  if (lastSent.time && !lastSent.sendCount) {
    node.warn(`Legacy lastSent format detected for ${scheduleKey}: ${JSON.stringify(lastSent)}. Resetting.`);
    delete lastSentCommands[scheduleKey];
    lastSent = { sendCount: 0, lastSentTime: null, scheduledTime: scheduleTimeStr, date: null };
  }

  // Handle legacy index-based keys (e.g., "33:0")
  const legacyKey = `${currentKey}:${originalIndex}`;
  if (lastSentCommands[legacyKey] && legacyKey !== scheduleKey) {
    node.warn(`Migrating legacy key ${legacyKey} to ${scheduleKey}: ${JSON.stringify(lastSentCommands[legacyKey])}`);
    lastSentCommands[scheduleKey] = lastSentCommands[legacyKey];
    delete lastSentCommands[legacyKey];
    lastSent = lastSentCommands[scheduleKey];
  }

  const currentTimeMs = currentTimeSP.getTime();
  const scheduleTimeMs = scheduleTime.getTime();
  const timeDiffMinutes = (currentTimeMs - scheduleTimeMs) / (1000 * 60);

  const withinWindow = timeDiffMinutes >= 0 && timeDiffMinutes <= 5;
  const canSend = lastSent.sendCount < 3;

  // Reset if from a previous day
  const lastSentDate = lastSent.date ? new Date(lastSent.date).setHours(0, 0, 0, 0) : null;
  const currDateMs = currDate.getTime();
  if (lastSentDate && lastSentDate !== currDateMs) {
    node.warn(`Resetting lastSent for ${scheduleKey} (from previous day: ${lastSent.date})`);
    delete lastSentCommands[scheduleKey];
    lastSent = { sendCount: 0, lastSentTime: null, scheduledTime: scheduleTimeStr, date: null };
  }

  // Check excluded days first
  let isExcluded = false;
  if (excludedDays.length > 0) {
    for (const excludedDay of excludedDays) {
      const excludedDate = new Date(transformDate(excludedDay));
      if (currDate.getTime() === excludedDate.getTime()) {
        isExcluded = true;
        node.warn(`Schedule ${scheduleTimeStr} for ${currentKey} blocked by excluded day`);
        break;
      }
    }
  }

  // Reset if outside window (for next day)
  if (timeDiffMinutes < 0 || timeDiffMinutes > 5) {
    if (lastSent.sendCount > 0) {
      node.warn(`Resetting lastSent for ${scheduleKey} (timeDiff: ${timeDiffMinutes} min)`);
      delete lastSentCommands[scheduleKey];
    }
    continue;
  }

  if (!isExcluded && withinWindow && canSend) {
    let shouldProcess = false;

    if (holiday) {
      if (storedHolidaysDays.length > 0) {
        for (const holidayDay of storedHolidaysDays) {
          const holidayDate = new Date(transformDate(holidayDay));
          if (currDate.getTime() === holidayDate.getTime()) {
            shouldProcess = true;
            node.warn(`Holiday match for ${scheduleTimeStr} on ${currentKey}`);
          }
        }
      }
    }

    if (daysWeek[currWeekDay]) {
      shouldProcess = true;
