const threePhaseMapping = flow.get('threePhaseMapping') || {};
const presenceConfig = flow.get('stored_presence_configuration') || {};

// Extract telemetry data
var telemetryPayload = msg.payload;
var messageType = telemetryPayload.message_type;
var slaveId = parseInt(telemetryPayload.id); // Ensure slaveId is a number
var telemetryOutput = {};
var msg2 = null; // For output 2 (presence command)
var msg3 = null; // For output 3 (no-presence command)

// Find all device names where infraredId matches slaveId
var deviceNames = Object.keys(devices).filter(function(key) {
    return devices[key].infraredId === slaveId;
});

// Handle different message types
if (messageType === "channel_update" && deviceNames.length > 0) {
    // Handle presence sensor telemetry
    var presenceValue = 0; // Default value
    var presenceChannel = telemetryPayload.channels.find(function(channel) { return channel.id === 0; });
    if (presenceChannel) {
        presenceValue = presenceChannel.value;
    }

    // Determine raw status: true if value is 0 (presence detected)
    var rawStatus = presenceValue === 0;
    var currentTime = new Date().getTime();

    // Get or initialize timestamps and flags from flow context
    var lastPresenceTimestamps = flow.get('lastPresenceTimestamps') || {};
    var presenceStartTimestamps = flow.get('presenceStartTimestamps') || {};
    var noPresenceStartTimestamps = flow.get('noPresenceStartTimestamps') || {};
    var previousStatus = flow.get('previousStatus') || {};

    // Process each matching device
    deviceNames.forEach(function(deviceName) {
        // Use deviceName to look up configuration
        var config = presenceConfig[deviceName] || { 
            presenceDetection: { enabled: true, triggerAfterSeconds: 240 },
            noPresenceDetection: { enabled: true, triggerAfterSeconds: 120 }
        };
        var hasConfig = !!presenceConfig[deviceName]; // Check if device has explicit config
        if (hasConfig) {
            // node.warn("Config for deviceName " + deviceName + ": " + JSON.stringify(config));
        }

        var presenceTriggerSeconds = config.presenceDetection && config.presenceDetection.triggerAfterSeconds !== undefined 
            ? config.presenceDetection.triggerAfterSeconds 
            : 240;
        var noPresenceTriggerSeconds = config.noPresenceDetection && config.noPresenceDetection.triggerAfterSeconds !== undefined 
            ? config.noPresenceDetection.triggerAfterSeconds 
            : 120;

        // Determine filtered status
        var filteredStatus = rawStatus;
        if (rawStatus) {
            // Presence detected: report immediately
            if (!presenceStartTimestamps[deviceName]) {
                presenceStartTimestamps[deviceName] = currentTime;
                flow.set('presenceStartTimestamps', presenceStartTimestamps);
            }

            // Clear no-presence timestamp if presence is detected
            if (noPresenceStartTimestamps[deviceName]) {
                delete noPresenceStartTimestamps[deviceName];
                flow.set('noPresenceStartTimestamps', noPresenceStartTimestamps);
            }

            lastPresenceTimestamps[deviceName] = currentTime;
            flow.set('lastPresenceTimestamps', lastPresenceTimestamps);

            // Log presence duration every 20 seconds (only for devices with config)
            if (hasConfig) {
                var timeSincePresenceStart = (currentTime - presenceStartTimestamps[deviceName]) / 1000;
                var lastPresenceLog = previousStatus[deviceName + "_lastPresenceLog"] || 0;
                if (timeSincePresenceStart >= lastPresenceLog + 20) {
                    node.warn("Presence on deviceName " + deviceName + " for " + Math.floor(timeSincePresenceStart) + "s");
                    previousStatus[deviceName + "_lastPresenceLog"] = Math.floor(timeSincePresenceStart / 20) * 20;
                    flow.set('previousStatus', previousStatus);
                }

                // Send presenceDetection.command after presenceTriggerSeconds of sustained presence
                if (timeSincePresenceStart >= presenceTriggerSeconds && !previousStatus[deviceName + "_presenceCommandSent"]) {
                    if (config.presenceDetection && config.presenceDetection.enabled && config.presenceDetection.command) {
                        msg2 = { payload: config.presenceDetection.command };
                        node.warn("DeviceName " + deviceName + ": sending presence command after " + presenceTriggerSeconds + "s");
                        previousStatus[deviceName + "_presenceCommandSent"] = true;
                        flow.set('previousStatus', previousStatus);
                    } else if (hasConfig) {
                        node.warn("DeviceName " + deviceName + ": no presence command configured");
                    }
                }
            }
        } else if (lastPresenceTimestamps[deviceName]) {
            // No presence: wait for presenceTriggerSeconds before reporting
            var timeSinceLastPresence = (currentTime - lastPresenceTimestamps[deviceName]) / 1000;

            if (timeSinceLastPresence < presenceTriggerSeconds) {
                filteredStatus = true; // Keep reporting presence until timeout
            } else {
                // No presence confirmed after presenceTriggerSeconds
                if (hasConfig) {
                    node.warn("No presence on deviceName " + deviceName + " after " + presenceTriggerSeconds + "s");
                }

                // Set no-presence start timestamp if not already set
                if (!noPresenceStartTimestamps[deviceName]) {
                    noPresenceStartTimestamps[deviceName] = currentTime;
                    flow.set('noPresenceStartTimestamps', noPresenceStartTimestamps);
                }

                // Log no-presence duration every 60 seconds (only for devices with config)
                if (hasConfig) {
                    var timeSinceNoPresenceStart = (currentTime - noPresenceStartTimestamps[deviceName]) / 1000;
                    var lastNoPresenceLog = previousStatus[deviceName + "_lastNoPresenceLog"] || 0;
                    if (timeSinceNoPresenceStart >= lastNoPresenceLog + 60 && timeSinceNoPresenceStart < noPresenceTriggerSeconds) {
                        var remainingTime = noPresenceTriggerSeconds - timeSinceNoPresenceStart;
                        node.warn("No presence on deviceName " + deviceName + " for " + Math.floor(timeSinceNoPresenceStart) + "s, waiting " + Math.floor(remainingTime) + " more seconds for noPresenceTrigger");
                        previousStatus[deviceName + "_lastNoPresenceLog"] = Math.floor(timeSinceNoPresenceStart / 60) * 60;
                        flow.set('previousStatus', previousStatus);
                    }
                }

                // Check if noPresenceTriggerSeconds has passed to send noPresenceDetection command
                var timeSinceNoPresenceStart = (currentTime - noPresenceStartTimestamps[deviceName]) / 1000;
                if (timeSinceNoPresenceStart >= noPresenceTriggerSeconds) {
                    // No-presence detection command (output 3)
                    if (config.noPresenceDetection && config.noPresenceDetection.enabled && config.noPresenceDetection.command) {
                        msg3 = { payload: config.noPresenceDetection.command };
                        if (hasConfig) {
                            node.warn("DeviceName " + deviceName + ": sending no-presence command after " + noPresenceTriggerSeconds + "s");
                        }
                    } else if (hasConfig) {
                        node.warn("DeviceName " + deviceName + ": no no-presence command configured");
                    }

                    // Clean up after sending command
                    delete lastPresenceTimestamps[deviceName];
                    delete presenceStartTimestamps[deviceName];
                    delete noPresenceStartTimestamps[deviceName];
                    delete previousStatus[deviceName + "_lastPresenceLog"];
                    delete previousStatus[deviceName + "_lastNoPresenceLog"];
                    delete previousStatus[deviceName + "_presenceCommandSent"];
                    flow.set('lastPresenceTimestamps', lastPresenceTimestamps);
                    flow.set('presenceStartTimestamps', presenceStartTimestamps);
                    flow.set('noPresenceStartTimestamps', noPresenceStartTimestamps);
                    flow.set('previousStatus', previousStatus);
                }
            }
        }

        // Update telemetry for this device
        if (devices[deviceName].type === "presence_sensor") {
            telemetryOutput[deviceName] = [
                {
                    ts: currentTime,
                    values: { status: filteredStatus }
                }
            ];
        }
    });

    // Handle targetDeviceNumbers for additional presence devices
    var targetDeviceNumbers = infraredMapping[slaveId] || [];
    if (targetDeviceNumbers.length > 0) {
        targetDeviceNumbers.forEach(function(deviceNumber) {
            var presenceDeviceName = deviceNumber + " - Presença";
            if (devices[presenceDeviceName] && devices[presenceDeviceName].type === "presence_sensor" && devices[presenceDeviceName].infraredId === slaveId && !telemetryOutput[presenceDeviceName]) {
                telemetryOutput[presenceDeviceName] = [
                    {
                        ts: currentTime,
                        values: { status: rawStatus }
                    }
                ];
            }
        });
    }
} else if (messageType === "infrared_update" && deviceNames.length > 0) {
    var temperature = telemetryPayload.temperature !== undefined ? telemetryPayload.temperature : telemetryPayload.value;
    if (temperature !== undefined) {
        var targetDeviceNumbers = infraredMapping[slaveId] || [];
        deviceNames.forEach(function(deviceName) {
            if (
                devices[deviceName].type === "remote_device" &&
                targetDeviceNumbers.indexOf(deviceName) !== -1
            ) {
                telemetryOutput[deviceName] = [
                    {
                        ts: new Date().getTime(),
                        values: { temperature: temperature }
                    }
                ];
            }
        });
    }
} else if (messageType === "consumption") {
    var phases = telemetryPayload.phases || {};
    var targetDeviceNumbers = threePhaseMapping[slaveId] || [];
    if (targetDeviceNumbers.length >= 3) {
        var phaseMapping = {
            a: targetDeviceNumbers[0],
