// Input: msg.payload contains the telemetry data
// Devices, infrared mapping, and three-phase mapping are stored in flow context
const devices = flow.get('devices') || {};
const infraredMapping = flow.get('infraredMapping') || {};
const threePhaseMapping = flow.get('threePhaseMapping') || {};

// Extract telemetry data
let telemetryPayload = msg.payload;
let messageType = telemetryPayload.message_type;
let slaveId = parseInt(telemetryPayload.id); // Ensure slaveId is a number
let telemetryOutput = {};

// Handle different message types
if (messageType === "channel_update") {
    // Handle presence sensor telemetry (for devices like "32 - Presença")
    let presenceValue = 0; // Default value

    // Find the presence channel (id: 0)
    let presenceChannel = telemetryPayload.channels.find(channel => channel.id === 0);
    if (presenceChannel) {
        presenceValue = presenceChannel.value;
    }

    // Determine status: true if value is 0, false if value > 0
    let status = presenceValue === 0;

    // Get the device numbers associated with this infrared slave
    let targetDeviceNumbers = infraredMapping[slaveId] || [];

    // If targetDeviceNumbers is empty, fall back to scanning all presence devices
    if (targetDeviceNumbers.length === 0) {
        Object.keys(devices).forEach(deviceName => {
            let device = devices[deviceName];
            if (device.type === "presence_sensor" && device.infraredId === slaveId) {
                telemetryOutput[deviceName] = [
                    {
                        ts: new Date().getTime(),
                        values: {
                            status: status
                        }
                    }
                ];
            }
        });
    } else {
        // Find presence devices with matching infraredId and name derived from targetDeviceNumbers
        targetDeviceNumbers.forEach(deviceNumber => {
            let presenceDeviceName = `${deviceNumber} - Presença`;
            let device = devices[presenceDeviceName];
            if (device) {
                if (device.type === "presence_sensor" && device.infraredId === slaveId) {
                    telemetryOutput[presenceDeviceName] = [
                        {
                            ts: new Date().getTime(),
                            values: {
                                status: status
                            }
                        }
                    ];
                }
            }
        });
    }
} else if (messageType === "infrared_update") {
    // Handle infrared device telemetry (for the specific device matching the slave's name)
    let temperature = telemetryPayload.temperature !== undefined ? telemetryPayload.temperature : telemetryPayload.value;

    if (temperature !== undefined) {
        let targetDeviceNumbers = infraredMapping[slaveId] || [];

        Object.keys(devices).forEach(deviceName => {
            let device = devices[deviceName];
            if (
                device.type === "remote_device" &&
                device.infraredId === slaveId &&
                targetDeviceNumbers.includes(deviceName)
            ) {
                telemetryOutput[deviceName] = [
                    {
                        ts: new Date().getTime(),
                        values: {
                            temperature: temperature
                        }
                    }
                ];
            }
        });
    }
} else if (messageType === "consumption") {
    // Handle energy consumption telemetry (for devices associated with the three-phase sensor)
    let phases = telemetryPayload.phases || {};

    // Get the device numbers associated with this three-phase sensor
    let targetDeviceNumbers = threePhaseMapping[slaveId] || [];

    if (targetDeviceNumbers.length >= 3) {
        // Map phases to devices: a -> first device, b -> second device, c -> third device

        let phaseMapping = {
            a: targetDeviceNumbers[0], // e.g., "3"
            b: targetDeviceNumbers[1], // e.g., "1"
            c: targetDeviceNumbers[2] // e.g., "11"
        };

        // Process each phase
        ['a', 'b', 'c'].forEach(phase => {
            let deviceNumber = phaseMapping[phase];
            let device = devices[deviceNumber];
            let consumptionValue = phases[phase] !== undefined ? phases[phase] : 0;

            if (device && device.type === "remote_device" && device.energyId === slaveId) {
                telemetryOutput[deviceNumber] = [
                    {
                        ts: new Date().getTime(),
                        values: {
                            consumption: consumptionValue // Changed from energyConsumption to consumption
                        }
                    }
                ];
            }
        });
    }
}

// Set the output
msg.payload = telemetryOutput;
return msg;

function encontrarPrimeiraParteDoNome(vetor, id) 
{
  const objeto = vetor.find(item => item.id === id);
  if (objeto) {
    const nomeSemPrefixo = objeto.name.replace(/^RM\s*/, '');
    const primeiraParte = nomeSemPrefixo.split(' ')[0];

    const convertido = Number(primeiraParte);

    return isNaN(convertido) ? primeiraParte : convertido;
  }
  return null;
}

function horaAtualEmSegundos() 
{
  const agora = new Date();
  const horas = agora.getHours();
  const minutos = agora.getMinutes();
  const segundos = agora.getSeconds();
  return (horas * 3600 + minutos * 60 + segundos);
}

